def detect_deadlock(processes):
    if not processes:
        return []

    # Map each resource to the process holding it
    resource_holder = {}
    for p in processes:
        for r in p["holds"]:
            resource_holder[r] = p["id"]

    # Build wait-for graph (functional graph: each node has at most 1 successor)
    wait_for = {}
    for p in processes:
        if p["waits"] is not None and p["waits"] in resource_holder:
            holder = resource_holder[p["waits"]]
            if holder != p["id"]:
                wait_for[p["id"]] = holder

    all_ids = {p["id"] for p in processes}
    in_cycle = set()
    # 0: unvisited, 1: in current path, 2: processed
    state = {pid: 0 for pid in all_ids}

    for start in all_ids:
        if state[start] != 0:
            continue
        path = []
        node = start
        # Follow chain until dead end or previously visited node
        while node is not None and state.get(node, 2) == 0:
            state[node] = 1
            path.append(node)
            node = wait_for.get(node)
        # If we stopped at a node that's in the current path, we have a cycle
        if node is not None and node in state and state[node] == 1:
            cycle_start_idx = path.index(node)
            for i in range(cycle_start_idx, len(path)):
                in_cycle.add(path[i])
        # Mark all nodes in path as done
        for p in path:
            state[p] = 2

    return sorted(list(in_cycle))

