import unittest

class TestSolution(unittest.TestCase):

    def test_simple_two_process_deadlock(self):
        processes = [
            {"id": 0, "holds": ["R1"], "waits": "R2"},
            {"id": 1, "holds": ["R2"], "waits": "R1"},
        ]
        self.assertEqual(detect_deadlock(processes), [0, 1])

    def test_no_deadlock_chain(self):
        processes = [
            {"id": 0, "holds": ["R1"], "waits": "R2"},
            {"id": 1, "holds": ["R2"], "waits": None},
        ]
        self.assertEqual(detect_deadlock(processes), [])

    def test_three_way_cycle(self):
        processes = [
            {"id": 0, "holds": ["A"], "waits": "B"},
            {"id": 1, "holds": ["B"], "waits": "C"},
            {"id": 2, "holds": ["C"], "waits": "A"},
        ]
        self.assertEqual(detect_deadlock(processes), [0, 1, 2])

    def test_hidden_empty_input(self):
        self.assertEqual(detect_deadlock([]), [])

    def test_hidden_single_process_no_wait(self):
        processes = [{"id": 5, "holds": ["X"], "waits": None}]
        self.assertEqual(detect_deadlock(processes), [])

    def test_hidden_wait_for_unheld_resource(self):
        processes = [
            {"id": 0, "holds": ["A"], "waits": "Z"},
            {"id": 1, "holds": ["B"], "waits": "Y"},
        ]
        self.assertEqual(detect_deadlock(processes), [])

    def test_hidden_chain_into_cycle(self):
        # P0 -> P1 -> P2 -> P1 (cycle is P1, P2 only)
        processes = [
            {"id": 0, "holds": ["A"], "waits": "B"},
            {"id": 1, "holds": ["B"], "waits": "C"},
            {"id": 2, "holds": ["C"], "waits": "B"},
            {"id": 3, "holds": ["D"], "waits": "E"},
            {"id": 4, "holds": ["E"], "waits": None},
            {"id": 5, "holds": ["F"], "waits": None},
        ]
        self.assertEqual(detect_deadlock(processes), [1, 2])

    def test_hidden_two_separate_cycles(self):
        processes = [
            {"id": 10, "holds": ["R1"], "waits": "R2"},
            {"id": 20, "holds": ["R2"], "waits": "R1"},
            {"id": 30, "holds": ["R3"], "waits": "R4"},
            {"id": 40, "holds": ["R4"], "waits": "R3"},
        ]
        self.assertEqual(detect_deadlock(processes), [10, 20, 30, 40])

    def test_hidden_large_single_cycle(self):
        n = 200
        processes = [
            {"id": i, "holds": [f"R{i}"], "waits": f"R{(i+1) % n}"}
            for i in range(n)
        ]
        self.assertEqual(detect_deadlock(processes), list(range(n)))

    def test_hidden_process_waits_for_own_resource(self):
        # A process waiting for a resource it already holds: no deadlock
        processes = [
            {"id": 0, "holds": ["A", "B"], "waits": "A"},
            {"id": 1, "holds": ["C"], "waits": None},
        ]
        self.assertEqual(detect_deadlock(processes), [])

    def test_hidden_mixed_cycle_and_free(self):
        # Cycle: 1->2->3->1, plus free processes and a chain
        processes = [
            {"id": 0, "holds": ["X"], "waits": "Y"},  # points to 1
            {"id": 1, "holds": ["Y"], "waits": "Z"},
            {"id": 2, "holds": ["Z"], "waits": "W"},
            {"id": 3, "holds": ["W"], "waits": "Y"},  # back to 1
            {"id": 4, "holds": ["V"], "waits": None},
        ]
        self.assertEqual(detect_deadlock(processes), [1, 2, 3])

if __name__ == '__main__':
    unittest.main()
